import { useState, useEffect, useRef, useCallback } from "react";
import axios from "axios";
import "./styles.css";

/* ─── Types ─────────────────────────────────────────────── */
interface WeatherData {
  name: string;
  sys: { country: string; sunrise: number; sunset: number };
  weather: { icon: string; description: string; id: number }[];
  main: {
    temp: number;
    humidity: number;
    feels_like: number;
    temp_min: number;
    temp_max: number;
    pressure: number;
  };
  wind: { speed: number; deg: number };
  visibility: number;
}

/* ─── Helpers ────────────────────────────────────────────── */
function fmtTime(unix: number): string {
  return new Date(unix * 1000).toLocaleTimeString([], {
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
}

function fmtClock(d: Date): string {
  return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false });
}

function uvFromWeatherId(id: number): number {
  if (id >= 800) return 7;
  if (id >= 700) return 2;
  if (id >= 600) return 1;
  if (id >= 500) return 2;
  if (id >= 300) return 3;
  return 4;
}

function uvLabel(uv: number): string {
  if (uv <= 2) return "Low";
  if (uv <= 5) return "Moderate";
  if (uv <= 7) return "High";
  if (uv <= 10) return "Very High";
  return "Extreme";
}

/* ─── Animated canvas background ────────────────────────── */
function StarCanvas() {
  const ref = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const canvas = ref.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d")!;
    let raf: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    resize();
    window.addEventListener("resize", resize);

    // Generate static stars
    const stars = Array.from({ length: 120 }, () => ({
      x: Math.random(),
      y: Math.random(),
      r: Math.random() * 1.2 + 0.3,
      alpha: Math.random() * 0.5 + 0.1,
      speed: Math.random() * 0.003 + 0.001,
      phase: Math.random() * Math.PI * 2,
    }));

    // Floating orbs
    const orbs = [
      { cx: 0.75, cy: 0.15, rx: 0.28, ry: 0.22, color: "rgba(79,142,247,0.055)" },
      { cx: 0.1,  cy: 0.8,  rx: 0.22, ry: 0.18, color: "rgba(79,142,247,0.04)" },
      { cx: 0.5,  cy: 0.5,  rx: 0.35, ry: 0.28, color: "rgba(30,60,120,0.06)" },
    ];

    let t = 0;
    const draw = () => {
      const { width: w, height: h } = canvas;
      ctx.clearRect(0, 0, w, h);
      t += 0.005;

      // Orbs
      orbs.forEach((o) => {
        const gx = o.cx * w;
        const gy = o.cy * h;
        const grad = ctx.createRadialGradient(gx, gy, 0, gx, gy, o.rx * w);
        grad.addColorStop(0, o.color);
        grad.addColorStop(1, "transparent");
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, w, h);
      });

      // Stars
      stars.forEach((s) => {
        const pulse = Math.sin(t * s.speed * 200 + s.phase) * 0.3 + 0.7;
        ctx.beginPath();
        ctx.arc(s.x * w, s.y * h, s.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255,255,255,${s.alpha * pulse})`;
        ctx.fill();
      });

      raf = requestAnimationFrame(draw);
    };
    draw();

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
    };
  }, []);

  return <canvas ref={ref} className="bg-canvas" />;
}

/* ─── Wind compass dial ──────────────────────────────────── */
function WindDial({ deg, speed }: { deg: number; speed: number }) {
  const dirs = ["N", "E", "S", "W"];
  const r = 54;
  const cx = 60;
  const cy = 60;

  const ticks = Array.from({ length: 36 }, (_, i) => {
    const angle = (i / 36) * 360;
    const rad = (angle * Math.PI) / 180;
    const major = i % 9 === 0;
    const inner = r - (major ? 8 : 4);
    const outer = r - 1;
    return {
      x1: cx + inner * Math.sin(rad),
      y1: cy - inner * Math.cos(rad),
      x2: cx + outer * Math.sin(rad),
      y2: cy - outer * Math.cos(rad),
      major,
    };
  });

  const needleRad = (deg * Math.PI) / 180;
  const needleLen = r - 12;

  return (
    <div className="dial-wrap">
      <svg viewBox="0 0 120 120" className="dial-svg">
        <circle cx={cx} cy={cy} r={r} className="dial-ring" />
        <circle cx={cx} cy={cy} r={r - 2} className="dial-inner" />

        {ticks.map((tk, i) => (
          <line
            key={i}
            x1={tk.x1} y1={tk.y1} x2={tk.x2} y2={tk.y2}
            className={tk.major ? "tick-major" : "tick-minor"}
          />
        ))}

        {dirs.map((d, i) => {
          const a = (i / 4) * 2 * Math.PI;
          const lr = r - 18;
          return (
            <text
              key={d}
              x={cx + lr * Math.sin(a)}
              y={cy - lr * Math.cos(a) + 2.5}
              textAnchor="middle"
              className="dial-label"
            >
              {d}
            </text>
          );
        })}

        {/* Needle tail */}
        <line
          x1={cx}
          y1={cy}
          x2={cx - (needleLen * 0.4) * Math.sin(needleRad)}
          y2={cy + (needleLen * 0.4) * Math.cos(needleRad)}
          stroke="rgba(255,255,255,0.18)"
          strokeWidth="1.5"
        />
        {/* Needle */}
        <line
          x1={cx}
          y1={cy}
          x2={cx + needleLen * Math.sin(needleRad)}
          y2={cy - needleLen * Math.cos(needleRad)}
          className="needle"
        />
        <circle cx={cx} cy={cy} r={3} className="needle-hub" />
      </svg>

      <div className="dial-value">
        {speed.toFixed(1)}
        <span className="dial-unit"> m/s</span>
      </div>
    </div>
  );
}

/* ─── Search icon ────────────────────────────────────────── */
const SearchIcon = () => (
  <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round">
    <circle cx="11" cy="11" r="7" />
    <line x1="16.5" y1="16.5" x2="21" y2="21" />
  </svg>
);

const SpinIcon = () => (
  <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" className="spin">
    <path d="M21 12a9 9 0 1 1-6.219-8.56" />
  </svg>
);

const CloudIcon = () => (
  <svg width="52" height="52" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round" className="empty-icon">
    <path d="M17.5 19H9a7 7 0 1 1 6.71-9h1.79a4.5 4.5 0 1 1 0 9Z" />
  </svg>
);

const SunriseIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
    <path d="M12 2v2M4.93 4.93l1.41 1.41M20.07 4.93l-1.41 1.41M3 12h2M19 12h2" />
    <path d="M12 6a6 6 0 0 1 6 6H6a6 6 0 0 1 6-6z" />
    <line x1="2" y1="20" x2="22" y2="20" />
    <polyline points="5 17 7 15" />
    <polyline points="19 17 17 15" />
  </svg>
);

const SunsetIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
    <path d="M12 10v2M4.93 4.93l1.41 1.41M20.07 4.93l-1.41 1.41M3 12h2M19 12h2" />
    <path d="M12 6a6 6 0 0 1 6 6H6a6 6 0 0 1 6-6z" />
    <line x1="2" y1="20" x2="22" y2="20" />
    <polyline points="7 15 5 17" />
    <polyline points="17 15 19 17" />
  </svg>
);

/* ─── App ────────────────────────────────────────────────── */
export default function App() {
  const [city, setCity] = useState("");
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [clock, setClock] = useState(new Date());
  const inputRef = useRef<HTMLInputElement>(null);

  const API_KEY = "e707cf0cf6c6b09c949bb02e32bf1c42";

  // Live clock
  useEffect(() => {
    const id = setInterval(() => setClock(new Date()), 1000);
    return () => clearInterval(id);
  }, []);

  const fetchWeather = useCallback(async () => {
    if (!city.trim()) {
      setError("Enter a city name to get started");
      setWeather(null);
      return;
    }
    try {
      setLoading(true);
      setError("");
      const res = await axios.get<WeatherData>(
        `https://api.openweathermap.org/data/2.5/weather?q=${city.trim()}&appid=${API_KEY}&units=metric`
      );
      setWeather(res.data);
    } catch {
      setWeather(null);
      setError("City not found — check the spelling and try again");
    } finally {
      setLoading(false);
    }
  }, [city]);

  const uv = weather ? uvFromWeatherId(weather.weather[0].id) : 0;

  return (
    <div className="app">
      <StarCanvas />

      <div className="shell">
        {/* Topbar */}
        <div className="topbar">
          <div className="brand">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M17.5 19H9a7 7 0 1 1 6.71-9h1.79a4.5 4.5 0 1 1 0 9Z" />
            </svg>
            Climate
          </div>
          <div className="topbar-time">{fmtClock(clock)}</div>
        </div>

        {/* Search */}
        <div className="search-block">
          <div className="search-row">
            <input
              ref={inputRef}
              className="search-input"
              type="text"
              placeholder="Search city…"
              value={city}
              onChange={(e) => setCity(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && fetchWeather()}
              autoComplete="off"
              spellCheck={false}
            />
            <button
              className="search-btn"
              onClick={fetchWeather}
              disabled={loading}
              aria-label="Search"
            >
              {loading ? <SpinIcon /> : <SearchIcon />}
            </button>
          </div>
          {error && <div className="error-msg">{error}</div>}
        </div>

        {/* Content */}
        {!weather ? (
          <div className="empty-state">
            <CloudIcon />
            <p>Search for a city to see its weather</p>
          </div>
        ) : (
          <div className="weather-grid fade-in">
            {/* ── Hero ── */}
            <div className="card hero-card">
              <div className="card-label">Current conditions</div>
              <div className="hero-location">
                <span className="hero-city">{weather.name}</span>
                <span className="hero-country">{weather.sys.country}</span>
              </div>
              <div className="hero-main">
                <img
                  className="hero-icon"
                  src={`https://openweathermap.org/img/wn/${weather.weather[0].icon}@4x.png`}
                  alt={weather.weather[0].description}
                />
                <div>
                  <div className="hero-temp-block">
                    <span className="hero-temp">{Math.round(weather.main.temp)}</span>
                    <span className="hero-unit">°C</span>
                  </div>
                  <div className="hero-desc">{weather.weather[0].description}</div>
                  <div className="hero-range">
                    <span>↑ {Math.round(weather.main.temp_max)}°</span>
                    <span className="dot-sep">·</span>
                    <span>↓ {Math.round(weather.main.temp_min)}°</span>
                    <span className="dot-sep">·</span>
                    <span>Feels {Math.round(weather.main.feels_like)}°</span>
                  </div>
                </div>
              </div>
            </div>

            {/* ── Wind ── */}
            <div className="card wind-card">
              <div className="card-label">Wind</div>
              <WindDial deg={weather.wind.deg} speed={weather.wind.speed} />
              <div className="card-sub" style={{ textAlign: "center", marginTop: 6 }}>
                {weather.wind.deg}° bearing
              </div>
            </div>

            {/* ── Humidity ── */}
            <div className="card humidity-card">
              <div className="card-label">Humidity</div>
              <div className="big-value">
                {weather.main.humidity}
                <span className="big-unit">%</span>
              </div>
              <div className="hbar-wrap">
                <div className="hbar-track">
                  <div className="hbar-fill" style={{ width: `${weather.main.humidity}%` }} />
                </div>
                <div className="hbar-labels">
                  <span>0</span>
                  <span>50</span>
                  <span>100</span>
                </div>
              </div>
              <div className="card-sub">
                {weather.main.humidity < 30
                  ? "Dry air — consider a humidifier"
                  : weather.main.humidity > 70
                  ? "High moisture in the air"
                  : "Comfortable humidity"}
              </div>
            </div>

            {/* ── Sun ── */}
            <div className="card sun-card">
              <div className="card-label">Daylight</div>
              <div className="sun-row">
                <div className="sun-item">
                  <SunriseIcon />
                  <span className="sun-label">Sunrise</span>
                  <span className="sun-time">{fmtTime(weather.sys.sunrise)}</span>
                </div>
                <div className="sun-divider" />
                <div className="sun-item">
                  <SunsetIcon />
                  <span className="sun-label">Sunset</span>
                  <span className="sun-time">{fmtTime(weather.sys.sunset)}</span>
                </div>
              </div>
            </div>

            {/* ── UV ── */}
            <div className="card uv-card">
              <div className="card-label">UV Index</div>
              <div className="uv-val">{uv}</div>
              <div className="card-sub">{uvLabel(uv)}</div>
            </div>

            {/* ── Pressure ── */}
            <div className="card pressure-card">
              <div className="card-label">Pressure</div>
              <div className="big-value">
                {weather.main.pressure}
                <span className="big-unit"> hPa</span>
              </div>
              <div className="card-sub">
                {weather.main.pressure > 1013 ? "High pressure system" : "Low pressure system"}
              </div>
            </div>

            {/* ── Visibility ── */}
            <div className="card vis-card">
              <div className="card-label">Visibility</div>
              <div className="big-value">
                {(weather.visibility / 1000).toFixed(1)}
                <span className="big-unit"> km</span>
              </div>
              <div className="card-sub">
                {weather.visibility >= 10000
                  ? "Clear and unrestricted"
                  : weather.visibility >= 5000
                  ? "Moderate visibility"
                  : "Reduced visibility"}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
